+//! MoE (Mixture of Experts) subsystem
+//!
+//! This module provides GPU-accelerated MoE operations for models like Mixtral.
+//!
+//! Components:
+//! - types.zig: Shared data structures
+//! - ../moe_metal.zig: Main MetalMoEEngine (GPU kernels)
+//! - ../expert_cache.zig: Hot expert caching
+//! - ../double_buffer.zig: Double-buffered SSD streaming
+//! - ../token_batch_loader.zig: Batched token loading
+
+pub const types = @import("types.zig");
+
+// Re-export commonly used types
+pub const ResidentLayerWeights = types.ResidentLayerWeights;
+pub const HotCacheStats = types.HotCacheStats;
+pub const OracleStats = types.OracleStats;
+pub const TurboStats = types.TurboStats;
+pub const ShadowRouterStats = types.ShadowRouterStats;
+pub const PinnedExpertBuffers = types.PinnedExpertBuffers;
+pub const PrefetchedBuffers = types.PrefetchedBuffers;
+pub const MoEConfig = types.MoEConfig;
+
+// Constants
+pub const MAX_LAYERS = types.MAX_LAYERS;
+pub const MAX_EXPERTS = types.MAX_EXPERTS;
+pub const MAX_PINNED_EXPERTS = types.MAX_PINNED_EXPERTS;
+pub const MAX_BATCH_SIZE = types.MAX_BATCH_SIZE;
+
+// Main engine (still in parent directory for now)
+pub const MetalMoEEngine = @import("../moe_metal.zig").MetalMoEEngine;
+
+test "moe module imports" {
+    _ = types;
+}
